CREATE TABLE "video2"."transcription_fragments" ("transcription_id" uuid NOT NULL, "sequence_number" integer NOT NULL, "completed_at" timestamptz, "failed_at" timestamptz, "started_at" Timestamp NOT NULL, "attempt_number" integer NOT NULL DEFAULT 1, "last_error" text NOT NULL, PRIMARY KEY ("transcription_id","sequence_number") , FOREIGN KEY ("transcription_id") REFERENCES "video2"."transcriptions"("id") ON UPDATE restrict ON DELETE restrict);COMMENT ON TABLE "video2"."transcription_fragments" IS E'Representing individual slices of a transcription';
